import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useNavigate, useParams } from "react-router-dom";
import { toast } from "react-toastify";
import { addNotification } from "../notificationReducer";

function EditCourse() {
  const { id } = useParams();
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const user = useSelector((state) => state.auth.user);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [course, setCourse] = useState(null);
  const [file, setFile] = useState(null);

  useEffect(() => {
    if (!user) {
      navigate("/login");
      return;
    }

    fetch(`http://localhost:3001/courses/${id}`)
      .then((res) => res.json())
      .then((data) => {
        if (user.role !== "admin" && (user.role === "teacher" && data.teacherId !== user.id)) {
          navigate("/dashboard");
        } else {
          setCourse(data);
          setName(data.name);
          setDescription(data.description);
        }
      })
      .catch((error) => {
        console.error("Error fetching course:", error);
        toast.error("Failed to load course");
      });
  }, [id, user, dispatch, navigate]);

  async function handleSubmit(e) {
    e.preventDefault();
    const updatedCourse = { ...course, name, description };

    const response = await fetch(`http://localhost:3001/courses/${id}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(updatedCourse),
    });

    if (response.ok) {
      if (file) {
        const fileFormData = new FormData();
        fileFormData.append("file", file);
        const fileResponse = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: fileFormData,
        });
        if (fileResponse.ok) {
          const { filePath } = await fileResponse.json();
          await fetch("http://localhost:3001/files", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              courseId: id,
              fileName: file.name,
              filePath,
            }),
          });
        }
      }
      dispatch(addNotification({
        id: Date.now(),
        userId: user.id,
        message: `Course ${name} updated!`,
        createdAt: new Date().toISOString(),
      }));
      await fetch("http://localhost:3001/notifications", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: user.id,
          message: `Course ${name} updated!`,
          createdAt: new Date().toISOString(),
        }),
      });
      toast.success("Course updated successfully!");
      navigate("/courses");
    } else {
      toast.error("Failed to update course.");
    }
  }

  if (!course) return <div className="page-container">Loading...</div>;

  return (
    <div className="page-container">
      <div className="form-container">
        <h1>Edit Course</h1>
        <div className="form-container">
          <input
            type="text"
            placeholder="Course Name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
          />
          <input
            type="text"
            placeholder="Description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
          />
          <input
            type="file"
            onChange={(e) => setFile(e.target.files[0])}
            accept=".pdf,.docx,.jpg,.png"
          />
          <button onClick={handleSubmit}>Update Course</button>
        </div>
      </div>
    </div>
  );
}

export default EditCourse;
